#include <stdio.h>
#include <string.h>

int main() {
    int Q; if (scanf("%d", &Q)!=1) return 0;
    while (Q--) {
        int N; scanf("%d", &N);
        char S[1005], T[1005], U[1005];
        scanf("%s %s %s", S, T, U);
        int K = (T[0] - S[0] + 26) % 26;
        for (int i = 0; i < N; ++i) {
            U[i] = (char)('a' + (U[i] - 'a' + K) % 26);
        }
        U[N] = '\0';
        printf("%s\n", U);
    }
    return 0;
}

