const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const Q = parseInt(input[idx++], 10);
let outputs = [];
for (let q = 0; q < Q; q++) {
  const N = parseInt(input[idx++], 10);
  const S = input[idx++];
  const T = input[idx++];
  const U = input[idx++];
  const K = (T.charCodeAt(0) - S.charCodeAt(0) + 26) % 26;
  let res = '';
  for (let i = 0; i < U.length; i++) {
    const ch = U.charCodeAt(i);
    const newCh = ((ch - 97 + K) % 26) + 97;
    res += String.fromCharCode(newCh);
  }
  outputs.push(res);
}
